-- =============================================
-- GraphHire 图谱智聘 - PostgreSQL 初始化数据
-- 版本: v1.1
-- 更新: 2026-06-12
-- 说明: 从当前 graphhire 数据库重新导出的基础数据；不包含已废弃收藏、通知、聊天等运行态数据。
-- =============================================

-- 测试账号密码沿用当前数据库 BCrypt 密文；本脚本只用于本地/测试环境基线初始化。

-- =============================================
-- 行业字典（当前库完整数据），共 72 条
-- =============================================
ON CONFLICT (id) DO UPDATE SET
    name = EXCLUDED.name,
    enabled = EXCLUDED.enabled,
    sort = EXCLUDED.sort,
    create_time = EXCLUDED.create_time,
    update_time = EXCLUDED.update_time,
    deleted = EXCLUDED.deleted,
    parent_id = EXCLUDED.parent_id,
    level = EXCLUDED.level;

-- =============================================
-- 职位类型字典（当前库完整数据），共 984 条
-- =============================================
ON CONFLICT (id) DO UPDATE SET
    name = EXCLUDED.name,
    parent_id = EXCLUDED.parent_id,
    level = EXCLUDED.level,
    sort_no = EXCLUDED.sort_no,
    status = EXCLUDED.status,
    create_time = EXCLUDED.create_time,
    update_time = EXCLUDED.update_time,
    deleted = EXCLUDED.deleted;

-- =============================================
-- 职位类型技能画像（当前库完整数据），共 849 条
-- =============================================
ON CONFLICT (id) DO UPDATE SET
    position_type_id = EXCLUDED.position_type_id,
    profile_json = EXCLUDED.profile_json,
    create_time = EXCLUDED.create_time,
    update_time = EXCLUDED.update_time,
    deleted = EXCLUDED.deleted;

-- =============================================
-- 技能标签，共 99 条
-- =============================================
ON CONFLICT (id) DO UPDATE SET
    name = EXCLUDED.name,
    synonyms = EXCLUDED.synonyms,
    create_time = EXCLUDED.create_time,
    update_time = EXCLUDED.update_time;

-- =============================================
-- 用户账号，共 52 条
-- =============================================
ON CONFLICT (id) DO UPDATE SET
    username = EXCLUDED.username,
    password = EXCLUDED.password,
    user_type = EXCLUDED.user_type,
    company_id = EXCLUDED.company_id,
    status = EXCLUDED.status,
    last_login_time = EXCLUDED.last_login_time,
    create_time = EXCLUDED.create_time,
    update_time = EXCLUDED.update_time,
    deleted = EXCLUDED.deleted;

-- =============================================
-- 公司，共 16 条
-- =============================================
ON CONFLICT (id) DO UPDATE SET
    user_id = EXCLUDED.user_id,
    name = EXCLUDED.name,
    code = EXCLUDED.code,
    license_path = EXCLUDED.license_path,
    auth_status = EXCLUDED.auth_status,
    scale = EXCLUDED.scale,
    address = EXCLUDED.address,
    contact = EXCLUDED.contact,
    phone = EXCLUDED.phone,
    create_time = EXCLUDED.create_time,
    update_time = EXCLUDED.update_time,
    deleted = EXCLUDED.deleted,
    avatar_path = EXCLUDED.avatar_path,
    industry_id = EXCLUDED.industry_id,
    description = EXCLUDED.description,
    website = EXCLUDED.website;

-- =============================================
-- 公司员工，共 32 条
-- =============================================
ON CONFLICT (id) DO UPDATE SET
    user_id = EXCLUDED.user_id,
    company_id = EXCLUDED.company_id,
    post = EXCLUDED.post,
    create_time = EXCLUDED.create_time,
    update_time = EXCLUDED.update_time,
    status = EXCLUDED.status;

-- =============================================
-- 个人资料，共 17 条
-- =============================================
ON CONFLICT (id) DO UPDATE SET
    user_id = EXCLUDED.user_id,
    real_name = EXCLUDED.real_name,
    gender = EXCLUDED.gender,
    age = EXCLUDED.age,
    education = EXCLUDED.education,
    city = EXCLUDED.city,
    target_city = EXCLUDED.target_city,
    phone = EXCLUDED.phone,
    email = EXCLUDED.email,
    create_time = EXCLUDED.create_time,
    update_time = EXCLUDED.update_time,
    deleted = EXCLUDED.deleted,
    avatar_url = EXCLUDED.avatar_url,
    expected_salary = EXCLUDED.expected_salary,
    school = EXCLUDED.school,
    expected_position_type_ids = EXCLUDED.expected_position_type_ids,
    default_position_type_id = EXCLUDED.default_position_type_id;

-- 简历和匹配记录属于用户上传/运行态数据，不能进入初始化脚本，避免泄露个人信息。

-- =============================================
-- 职位，共 72 条
-- =============================================
ON CONFLICT (id) DO UPDATE SET
    company_id = EXCLUDED.company_id,
    title = EXCLUDED.title,
    city = EXCLUDED.city,
    salary_min = EXCLUDED.salary_min,
    salary_max = EXCLUDED.salary_max,
    salary_unit = EXCLUDED.salary_unit,
    experience = EXCLUDED.experience,
    job_type = EXCLUDED.job_type,
    status = EXCLUDED.status,
    create_time = EXCLUDED.create_time,
    update_time = EXCLUDED.update_time,
    deleted = EXCLUDED.deleted,
    description = EXCLUDED.description,
    skills = EXCLUDED.skills,
    position_type_id = EXCLUDED.position_type_id,
    education = EXCLUDED.education,
    owner_user_id = EXCLUDED.owner_user_id;


-- =============================================
-- 序列校准
-- =============================================
SELECT setval(pg_get_serial_sequence('industry', 'id'), COALESCE((SELECT MAX(id) FROM industry), 1), true);
SELECT setval(pg_get_serial_sequence('position_type', 'id'), COALESCE((SELECT MAX(id) FROM position_type), 1), true);
SELECT setval(pg_get_serial_sequence('position_type_skill_profile', 'id'), COALESCE((SELECT MAX(id) FROM position_type_skill_profile), 1), true);
SELECT setval(pg_get_serial_sequence('skill_tag', 'id'), COALESCE((SELECT MAX(id) FROM skill_tag), 1), true);
SELECT setval(pg_get_serial_sequence('sys_user', 'id'), COALESCE((SELECT MAX(id) FROM sys_user), 1), true);
SELECT setval(pg_get_serial_sequence('company', 'id'), COALESCE((SELECT MAX(id) FROM company), 1), true);
SELECT setval(pg_get_serial_sequence('company_staff', 'id'), COALESCE((SELECT MAX(id) FROM company_staff), 1), true);
SELECT setval(pg_get_serial_sequence('person_info', 'id'), COALESCE((SELECT MAX(id) FROM person_info), 1), true);
SELECT setval(pg_get_serial_sequence('job', 'id'), COALESCE((SELECT MAX(id) FROM job), 1), true);
